type (
	BulkDeleteSubjectsResponse = interface{}
	BulkDeleteSubjectsHandler  httptransport.Handler[BulkDeleteSubjectsRequest, BulkDeleteSubjectsResponse]
)

type BulkDeleteSubjectsRequest struct {
	namespace string
	ids       []string
}

func (h *handler) BulkDeleteSubjects() BulkDeleteSubjectsHandler {
	return httptransport.NewHandler(
		func(ctx context.Context, r *http.Request) (BulkDeleteSubjectsRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return BulkDeleteSubjectsRequest{}, err
			}
			var body struct{ IDs []string }
			if err := commonhttp.JSONRequestBodyDecoder(r, &body); err != nil {
				return BulkDeleteSubjectsRequest{}, err
			}
			return BulkDeleteSubjectsRequest{namespace: ns, ids: body.IDs}, nil
		},
		func(ctx context.Context, req BulkDeleteSubjectsRequest) (BulkDeleteSubjectsResponse, error) {
			for _, id := range req.ids {
				if err := h.subjectService.Delete(ctx, models.NamespacedID{Namespace: req.namespace, ID: id}); err != nil {
					return nil, fmt.Errorf("failed to delete subject %s: %w", id, err)
				}
			}
			return nil, nil
		},
		commonhttp.EmptyResponseEncoder[BulkDeleteSubjectsResponse](http.StatusNoContent),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("bulkDeleteSubjects"))...,
	)
}
